491	
492	    let cloud = rbtdrp_read_env_value(&rbrd, RBTDRP_FIELD_RBRD_CLOUD_PREFIX).unwrap_or_default();
493	    let runtime =
494	        rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
495	
496	    if cloud == cloud_target && runtime == runtime_target {
497	        return Ok(());
498	    }
499	
500	    if cloud != cloud_target {
501	        let content = std::fs::read_to_string(&rbrd)
502	            .map_err(|e| format!("rbtdrp: read {}: {}", rbrd.display(), e))?;
503	        let new_content = rbtdrp_replace_env_fields(
504	            &content,
505	            &[(RBTDRP_FIELD_RBRD_CLOUD_PREFIX, cloud_target.as_str())],
506	        );
507	        std::fs::write(&rbrd, &new_content)
508	            .map_err(|e| format!("rbtdrp: write {}: {}", rbrd.display(), e))?;
509	    }
510	
511	    if runtime != runtime_target {
512	        let content = std::fs::read_to_string(&rbrr)
513	            .map_err(|e| format!("rbtdrp: read {}: {}", rbrr.display(), e))?;
514	        let new_content = rbtdrp_replace_env_fields(
515	            &content,
516	            &[(RBTDRP_FIELD_RBRR_RUNTIME_PREFIX, runtime_target.as_str())],
517	        );
518	        std::fs::write(&rbrr, &new_content)
519	            .map_err(|e| format!("rbtdrp: write {}: {}", rbrr.display(), e))?;
520	    }
521	
522	    let commit_msg = format!(
523	        "pristine-lifecycle fixture: install throwaway prefixes ({}/{})",
